/**
 * 将Markdown文本转换为纯文本
 * @param {string} markdown - 输入的Markdown格式文本
 * @returns {string} - 转换后的纯文本字符串
 */
function markdownToText(markdown) {
    if (!markdown) return '';

    let text = markdown;

    // 移除代码块
    text = text.replace(/```[\s\S]*?```/g, '');
    text = text.replace(/`([^`]+)`/g, '$1');

    // 移除标题符号
    text = text.replace(/^#{1,6}\s+/gm, '');

    // 移除粗体和斜体
    text = text.replace(/[*_]{2}([^*_]+)[*_]{2}/g, '$1'); // 粗体
    text = text.replace(/[*_]([^*_]+)[*_]/g, '$1'); // 斜体

    // 处理链接
    text = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1'); // [文本](链接)
    text = text.replace(/\[([^\]]+)\]\[[^\]]*\]/g, '$1'); // [文本][引用]

    // 移除图片标记
    text = text.replace(/!\[([^\]]*?)\]\([^)]+\)/g, '$1');

    // 处理各种非标准格式的图片标记
    // 处理类似 "!图片                )" 的情况
    text = text.replace(/!图片\s*\)/g, '');
    // 处理类似 "!图片                " 的情况（在行尾）
    text = text.replace(/!图片\s*$/g, '');
    // 处理任何以感叹号开头后跟"图片"的内容
    text = text.replace(/!图片[\s\S]*?\)/g, '');
    // 处理可能残留的右括号
    text = text.replace(/^\s*\)\s*$/gm, '');
    // 处理可能残留的空行
    text = text.replace(/^\s*$/gm, '');

    // 处理列表
    text = text.replace(/^[\s]*[\-*+]\s+/gm, ''); // 无序列表
    text = text.replace(/^[\s]*\d+\.\s+/gm, ''); // 有序列表

    // 处理引用
    text = text.replace(/^\s*>\s+/gm, '');

    // 处理水平分割线
    text = text.replace(/^\s*[-*_]{3,}\s*$/gm, '\n');

    // 移除SVG相关标签及其内容
    text = text.replace(/<svg[^>]*>(([\s\S]*?)<\/svg>)?/gi, '');

    // 增强SVG标签清理（包含自闭合标签和更多元素）
    const svgElements = 'svg|rect|circle|path|line|polygon|polyline|g|defs|use|symbol|ellipse|text|image|clipPath|mask|pattern|filter|marker|linearGradient|radialGradient|stop|tspan|textPath|animate|animateMotion|animateTransform|set|foreignObject|switch|desc|title|metadata';
    text = text.replace(new RegExp(`<(${svgElements})(\\s[^>]*)?\\/?>`,'gi'), '');
    text = text.replace(new RegExp(`<\\/(${svgElements})>`,'gi'), '');

    // 移除单独的SVG标签片段（如' rect /rect /g /g /svg'）
    text = text.replace(/[\s']+(?:rect|circle|path|g|svg|defs|use|symbol)\s*\/?/gi, ' ');
    text = text.replace(/[\s']+\/(?:rect|circle|path|g|svg|defs|use|symbol)\s*/gi, ' ');

    // 移除括号内的SVG标签片段
    text = text.replace(/\([^\)]*?(?:rect|circle|path|g|svg)[^\)]*?\)/gi, '');

    // 清理SVG属性和标签片段
    // 处理类似 ' fill=' FFFFFF' rect x='249' y='126' width='1' height='1' /rect /g /g /svg )' 的内容
    text = text.replace(/['"\s]+(fill|x|y|width|height|rx|ry|cx|cy|r|d|points|viewBox|xmlns)=['"]?[^'">\s]*['"]?/gi, ' ');
    text = text.replace(/\s+(?:\/)?(?:rect|circle|path|g|svg|defs|use|symbol|ellipse|text|image)(?:\s+|\/)/gi, ' ');
    text = text.replace(/\s+\/(?:rect|circle|path|g|svg|defs|use|symbol|ellipse|text|image)(?:\s+|$)/gi, ' ');

    // 移除SVG和HTML常见属性
    const commonAttributes = 'xmlns|version|viewBox|width|height|class|style|id|fill|stroke|d|points|transform|x|y|cx|cy|r|x1|y1|x2|y2|dx|dy|offset|gradientUnits|spreadMethod|patternUnits|patternTransform|markerWidth|markerHeight|refX|refY|orient|font-size|font-family|text-anchor|alignment-baseline|href|xlink:href|preserveAspectRatio';
    text = text.replace(new RegExp(`\\s+(${commonAttributes})=[\"\']([^\"\']*)[\"\'](?:\\s+|$)`,'gi'), ' ');

    // 移除data URI和编码内容
    text = text.replace(/data:(?:[^;]+;)*(?:base64,)?[a-zA-Z0-9+/]+={0,2}/g, '');
    text = text.replace(/%[0-9a-fA-F]{2}/g, ' ');

    // 最终清理：移除任何剩余的SVG相关内容
    // 处理括号中的SVG内容
    text = text.replace(/\([^\)]*(?:svg|rect|g|path|circle)[^\)]*\)/gi, '');
    // 处理引号中的SVG内容
    text = text.replace(/'[^']*(?:svg|rect|g|path|circle)[^']*'/gi, '');
    text = text.replace(/"[^"]*(?:svg|rect|g|path|circle)[^"]*"/gi, '');
    // 处理任何剩余的SVG标签片段
    text = text.replace(/(?:\/)?(?:svg|rect|g|path|circle|defs|use|symbol)(?:\/)?/gi, '');

    // 移除其他HTML标签
    text = text.replace(/<[^>]+>/g, '');

    // 处理转义字符
    text = text.replace(/\\([\\`*_{}\[\]()#+\-.!])/g, '$1');

    // 清理多余的空行
    text = text.replace(/\n\s*\n/g, '\n\n');
    text = text.replace(/^\s+|\s+$/g, '');

    return text;
}

/**
 * 将文本按指定长度分段
 * @param {string} text - 输入文本
 * @param {number} segmentLength - 每段文本的最大长度
 * @returns {string[]} - 分段后的文本数组
 */
function splitTextIntoSegments(text, segmentLength = 1800) {
    const segments = [];
    let remainingText = text;

    while (remainingText.length > 0) {
        if (remainingText.length <= segmentLength) {
            segments.push(remainingText);
            break;
        }

        let endIndex = segmentLength;
        // 尝试在句子或段落边界处分段
        const nextParagraph = remainingText.indexOf('\n\n', endIndex - 100);
        const nextSentence = remainingText.indexOf('. ', endIndex - 100);

        if (nextParagraph !== -1 && nextParagraph < endIndex + 100) {
            endIndex = nextParagraph;
        } else if (nextSentence !== -1 && nextSentence < endIndex + 100) {
            endIndex = nextSentence + 1;
        }

        segments.push(remainingText.substring(0, endIndex).trim());
        remainingText = remainingText.substring(endIndex).trim();
    }

    return segments;
}

// 示例输入
const markdownInput = $input.first().json.data.markdown;
const plainText = markdownToText(markdownInput);
const textSegments = splitTextIntoSegments(plainText);

// 将文本段落转换为规范的block对象格式
const blocks = textSegments.map(segment => ({
    object: 'block',
    type: 'paragraph',
    paragraph: {
        rich_text: [
            {
                type: 'text',
                annotations: {
                    bold: false,
                    strikethrough: false,
                    underline: false,
                    italic: false,
                    code: false,
                    color: 'default'
                },
                text: {
                    content: segment
                }
            }
        ]
    }
}));

return {
    blocks: blocks
};

// 获取 Firecrawl 爬取到的 Markdown 纯文本
const markdownText = $input.first().json.data.markdown;

// 过滤掉空行，将文本变成一行行的纯数据数组
const lines = markdownText.split('\n').filter(line => line.trim() !== '');

const results = [];
let currentArticle = {};
let tags = [];

// 遍历每一行，智能推导数据结构
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  // 使用正则提取图片链接里的 文章ID (即 cover_image/ 后面的那一串字符)
  const imgMatch = line.match(/!\[.*?\]\(.*\/cover_image\/([^\/]+)\//);

  if (imgMatch) {
    // 1. 如果匹配到了图片行，说明当前这篇完整文章的数据收集完毕了
    const articleId = imgMatch[1];

    // 🌟 核心智能：自动拼接出最完美的真实文章链接
    currentArticle.link = `https://www.jiqizhixin.com/articles/${articleId}`;

    if (tags.length > 0) {
      currentArticle.tags = [...tags]; // 保存标签
    }

    // 压入最终输出结果
    results.push({ json: currentArticle });

    // 清空缓存，准备装载下一篇文章
    currentArticle = {};
    tags = [];
  } else {
    // 2. 如果不是图片行，按顺序装填：第一行是标题，第二行是时间，中间夹着的是标签
    if (!currentArticle.title) {
      currentArticle.title = line.trim();
    } else if (!currentArticle.publishTime) {
      currentArticle.publishTime = line.trim();
    } else {
      // 标题和时间都有了，剩下的纯文本肯定是标签
      tags.push(line.trim());
    }
  }
}

// 输出完美的 JSON 结构给 n8n 的下一个节点
return results;

// 获取上一个节点传入的所有数据
const items = $input.all();

// 获取当前时间，用于推算年份
const now = new Date();
const currentYear = now.getFullYear();

// 遍历每一条数据进行时间转换
for (let item of items) {
  const rawTime = item.json.publishTime; // 例如："03月13日"

  if (rawTime) {
    // 使用正则提取月份和日期
    const match = rawTime.match(/(\d+)\s*月\s*(\d+)\s*日/);

    if (match) {
      // JavaScript 的 Date 对象中，月份是从 0 开始的（0代表1月，2代表3月）
      const month = parseInt(match[1], 10) - 1; 
      const day = parseInt(match[2], 10);

      // 构建日期对象，假设时间为当天的 00:00:00（你也可以根据需要改成 08:00:00 等）
      let publishDate = new Date(currentYear, month, day, 0, 0, 0);

      // 智能纠错（跨年处理）：如果算出来的日期比此时此刻还要晚，那这篇文章肯定是去年的
      if (publishDate > now) {
        publishDate.setFullYear(currentYear - 1);
      }

      // 核心：将其转换为 ISO 8601 字符串并覆写原字段
      item.json.publishTime = publishDate.toISOString();
    }
  }
}
for (let item of items) {
  // ... 之前处理时间的逻辑 ...

  // 核心补丁：确保 tags 永远存在，即使是空的
  if (!item.json.tags) {
    item.json.tags = []; // 或者赋值为 ""，取决于你 Notion 的字段类型
  }

  // 核心补丁：
  // 如果 tags 存在且是数组，用逗号连接成字符串
  // 如果 tags 不存在，给一个空字符串 "" 或者 "无标签"
  if (item.json.tags && Array.isArray(item.json.tags)) {
    item.json.tagText = item.json.tags.join(', '); 
  } else {
    item.json.tagText = ""; // Notion 接受空字符串，不会报错
  }

}
// 返回处理后的数据给下一个节点
return items;
